Still can't get this to work. The wiring is correct because I can get updated readings with the following sketch:

```sketch
/*

Example of BH1750 library usage.

This example initalises the BH1750 object using the default
high resolution mode and then makes a light level reading every second.

Connection:
 VCC-5v
 GND-GND
 SCL-SCL(analog pin 5)
 SDA-SDA(analog pin 4)
 ADD-NC or GND

*/

#include <Wire.h>
#include <BH1750.h>


BH1750 lightMeter;


void setup(){
  Serial.begin(9600);
  lightMeter.begin();
  Serial.println("Running...");
}


void loop() {
  uint16_t lux = lightMeter.readLightLevel();
  Serial.print("Light: ");
  Serial.print(lux);
  Serial.println(" lx");
  delay(1000);
}
```

I get `0.0` consistently with the following PyMata application though:

```
#!/usr/bin/env python
from PyMata.pymata import PyMata
import os
import time

board = PyMata(os.environ['ARDUINO_PORT'])
board.i2c_config(0, board.ANALOG, 4, 5)
board.i2c_write(0x23, board.I2C_READ_CONTINUOUSLY) # same results with board.I2C_READ

while True:
  try:
    board.i2c_read(0x23, 0, 2, board.I2C_READ) # same results with board.I2C_READ_CONTINUOUSLY
    time.sleep(3)

    data = board.i2c_get_read_data(0x23)
    print 'Got read data: %s' % data
    lux = (data[1] << 8 | data[2]) >> 4
    lux /= 1.2
    print str(lux) + ' lux'
  except KeyboardInterrupt:
    board.close()
```

